#include <stdint.h>

#include <stdint.h>

/* --- АДРЕСА РЕГИСТРОВ (из Reference Manual RM0008) --- */

// 1. Управление тактированием (RCC - Reset and Clock Control)
// Базовый адрес RCC: 0x4002 1000
#define RCC_BASE      0x40021000UL

// Регистр включения тактирования периферии APB2 (смещение 0x18)
#define RCC_APB2ENR   (*(volatile uint32_t *)(RCC_BASE + 0x18))

// 2. Порт ввода-вывода C (GPIOC)
// Базовый адрес GPIOC: 0x4001 1000
#define GPIOC_BASE    0x40011000UL

// Регистр конфигурации (High) для пинов 8-15 (смещение 0x04)
#define GPIOC_CRH     (*(volatile uint32_t *)(GPIOC_BASE + 0x04))

// Регистр данных на выходе (смещение 0x0C)
#define GPIOC_ODR     (*(volatile uint32_t *)(GPIOC_BASE + 0x0C))


/* --- РЕГИСТРЫ SYSTICK (встроены в ядро процессора) --- */
#define SYSTICK_BASE  0xE000E010UL
#define STK_CTRL      (*(volatile uint32_t *)(SYSTICK_BASE + 0x00)) // Управление и статус
#define STK_LOAD      (*(volatile uint32_t *)(SYSTICK_BASE + 0x04)) // Значение для перезагрузки
#define STK_VAL       (*(volatile uint32_t *)(SYSTICK_BASE + 0x08)) // Текущее значение

// 1. Глобальный счетчик миллисекунд.
// volatile обязателен: main должен знать, что значение меняется "извне" (в прерывании).
volatile uint32_t ms_ticks = 0;

// 2. Обработчик прерывания SysTick.
// Процессор вызывает эту функцию автоматически каждую 1 мс.
void SysTick_Handler(void) {
	ms_ticks++;
	}

// 3. Новая функция задержки.
// Она больше не блокирует таймер, а просто ждет, пока счетчик вырастет.
void delay_ms(uint32_t ms) {
	uint32_t start = ms_ticks;
	while ((ms_ticks - start) < ms);
	}

// Функция инициализации таймера (делаем один раз при старте)
/*
 *  ┌──────┬───────────┬──────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────┐
  │ Биты │ Имя       │ Описание                                                                                                                                                                 │
  ├──────┼───────────┼──────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────┤
  │ 0    │ ENABLE    │ 1 — Счетчик включен. 0 — Выключен.                                                                                                                                       │
  │ 1    │ TICKINT   │ 1 — РАЗРЕШИТЬ ПРЕРЫВАНИЕ! Если этот бит равен 1, то когда счетчик доходит до 0, генерируется исключение (Interrupt). Если 0 — прерывание не генерируется (Polling mode). │
  │ 2    │ CLKSOURCE │ Источник частоты. 1 — Внутренняя частота процессора (AHB). 0 — Внешняя частота (AHB/8).                                                                                  │
  │ 16   │ COUNTFLAG │ (Только для чтения) Становится 1, когда счетчик дошел до 0. Сбрасывается при чтении регистра.                                                                            │
  └──────┴───────────┴──────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────┘

 *
 */


void SysTick_Init(void) {
	// Настраиваем на 1 мс (при частоте 8 МГц это 8000 тактов)
	STK_LOAD = 8000 - 1;
	STK_VAL = 0;
	// Включаем: Bit 0 (ENABLE), Bit 1 (TICKINT - ПРЕРЫВАНИЕ!), Bit 2 (CLKSOURCE)
	STK_CTRL = (1 << 0) | (1 << 1) | (1 << 2);
	}




int main(void)
{
	// 1. Настройка PC13 на выход
	RCC_APB2ENR |= (1 << 4);
	GPIOC_CRH &= ~(0xF << 20);
	GPIOC_CRH |= (0x2 << 20);

	// 2. Инициализация таймера (теперь один раз!)
	SysTick_Init();

	while(1) {
		GPIOC_ODR ^= (1 << 13);
		delay_ms(500); // Работает на прерываниях
		}
}

